1	/**
2	 * state.js — State lifecycle and persistence for the design proof MCP server.
3	 * Orchestrates proof.js (element model, integrity) and metrics.js (completeness,
4	 * challenges, closure). Uses I/O for save/load.
5	 *
6	 * Necessary Conditions Model (v2):
7	 *   - Longer ID prefixes (EVID-, RULE-, PERM-, NCON-, RISK-) avoid collisions
8	 *   - No resolve operation (OPENs removed)
9	 *   - Tracks conditionCountHistory instead of openCountHistory
10	 */
11	
12	import { readFileSync, writeFileSync } from 'fs';
13	import { createElement, validateRefs, checkAllIntegrity } from './proof.js';
14	import { computeCompleteness, computeGroundingCoverage, detectChallenge, detectStall, checkClosure } from './metrics.js';
15	
16	const ID_PREFIX = {
17	  EVIDENCE: 'EVID-',
18	  RULE: 'RULE-',
19	  PERMISSION: 'PERM-',
20	  NECESSARY_CONDITION: 'NCON-',
21	  RISK: 'RISK-',
22	};
23	
24	/**
25	 * Create a clean initial state.
26	 * @param {string} problemStatement
27	 * @returns {object}
28	 */
29	export function initializeState(problemStatement) {
30	  return {
31	    round: 0,
32	    problemStatement,
33	    elements: new Map(),
34	    elementCounters: {
35	      EVIDENCE: 0, RULE: 0, PERMISSION: 0, NECESSARY_CONDITION: 0, RISK: 0,
36	    },
37	    conditionCountHistory: [],
38	    elementCountHistory: [],
39	    challengeModesUsed: [],
40	    challengeLog: [],
41	    revisionLog: [],
42	    phaseTransitionRound: 0,
43	  };
44	}
45	
46	/**
47	 * Generate a new element ID, incrementing the counter for the given type.
48	 * Returns [id, updatedState] without mutating the input.
49	 * @param {object} state
50	 * @param {string} type
51	 * @returns {[string, object]}
52	 */
53	export function generateId(state, type) {
54	  const newState = structuredClone(state);
55	  newState.elements = cloneElements(state.elements);
56	
57	  newState.elementCounters[type]++;
58	  const id = `${ID_PREFIX[type]}${newState.elementCounters[type]}`;
59	  return [id, newState];
60	}
61	
62	/**
63	 * Apply a batch of operations to the state. Processes sequentially so
64	 * later operations can reference elements added earlier in the batch.
65	 * Returns result object with updated state and metadata.
66	 * @param {object} state
67	 * @param {Array<object>} operations
68	 * @returns {object}
69	 */
70	export function applyOperations(state, operations) {
71	  let current = structuredClone(state);
72	  current.elements = cloneElements(state.elements);
73	
74	  current.round++;
75	
76	  const added = [];
77	  const revised = [];
78	  const withdrawn = [];
79	  const errors = [];
80	
81	  for (const op of operations) {
82	    switch (op.op) {
83	      case 'add': {
84	        // Validate grounding/basis refs against current elements
85	        const groundingRefs = op.grounding || [];
86	        const basisRefs = op.basis || [];
87	        const allRefs = [...groundingRefs, ...basisRefs];
88	        const refErrors = validateRefs(allRefs, current.elements);
89	        if (refErrors.length > 0) {
90	          errors.push(...refErrors);
91	          break;
92	        }
93	        const [id, newState] = generateId(current, op.type);
94	        current = newState;
95	        const element = createElement(op, id, current.round);
96	        current.elements.set(id, element);
97	        added.push(id);
98	        break;
99	      }
100	      case 'revise': {
101	        const target = current.elements.get(op.target);
102	        if (!target || target.status !== 'active') {
103	          errors.push(`Cannot revise "${op.target}": element not found or not active`);
104	          break;
105	        }
106	        if (op.statement !== undefined) target.statement = op.statement;
107	        if (op.grounding !== undefined) target.grounding = op.grounding;
108	        if (op.basis !== undefined) target.basis = op.basis;
109	        if (op.collapse_test !== undefined) target.collapse_test = op.collapse_test;
110	        if (op.reasoning_chain !== undefined) target.reasoning_chain = op.reasoning_chain;
111	        if (op.rejected_alternatives !== undefined) target.rejected_alternatives = op.rejected_alternatives;
112	        if (op.relieves !== undefined) target.relieves = op.relieves;
113	        target.revision++;
114	        target.revisedInRound = current.round;
115	        current.revisionLog.push({
116	          target: op.target,
117	          round: current.round,
118	          revision: target.revision,
119	        });
120	        revised.push(op.target);
121	        break;
122	      }
123	      case 'withdraw': {
124	        const target = current.elements.get(op.target);
125	        if (!target || target.status !== 'active') {
126	          errors.push(`Cannot withdraw "${op.target}": element not found or not active`);
127	          break;
128	        }
129	        target.status = 'withdrawn';
130	        withdrawn.push(op.target);
131	        break;
132	      }
133	      default:
134	        errors.push(`Unknown operation: ${op.op}`);
135	    }
136	  }
137	
138	  // Record history
139	  let activeConditions = 0;
140	  for (const [, el] of current.elements) {
141	    if (el.status === 'active' && el.type === 'NECESSARY_CONDITION') {
142	      activeConditions++;
143	    }
144	  }
145	  current.conditionCountHistory.push(activeConditions);
146	  current.elementCountHistory.push(current.elements.size);
147	
148	  // Compute post-operation metadata
149	  const integrityWarnings = checkAllIntegrity(current.elements);
150	  const completeness = {
151	    ...computeCompleteness(current.elements),
152	    groundingCoverage: computeGroundingCoverage(current.elements),
153	  };
154	  const challengeTrigger = detectChallenge(current);
155	  const stallDetected = detectStall(current.conditionCountHistory);
156	  const closure = checkClosure(current);
157	
158	  return {
159	    state: current,
160	    added,
161	    revised,
162	    withdrawn,
163	    errors,
164	    integrityWarnings,
165	    completeness,
166	    challengeTrigger,
167	    stallDetected,
168	    closure,
169	  };
170	}
