172	/**
173	 * Mark a challenge mode as used. Returns new state without mutating input.
174	 * @param {object} state
175	 * @param {string} mode
176	 * @returns {object}
177	 */
178	export function markChallengeUsed(state, mode) {
179	  const newState = structuredClone(state);
180	  newState.elements = cloneElements(state.elements);
181	  newState.challengeModesUsed.push(mode);
