1	/**
2	 * proof.js — Element model and integrity checks for the design proof MCP server.
3	 * Pure-functions module with no I/O.
4	 *
5	 * Necessary Conditions Model (v2):
6	 *   EVIDENCE   — codebase facts, agent-sourced, verifiable
7	 *   RULE       — designer-directed restrictions on the design space
8	 *   PERMISSION — designer-directed relief from an existing restriction
9	 *   NECESSARY_CONDITION — something that must be true for the design to hold
10	 *   RISK       — identified hazards attached to specific conditions
11	 */
12	
13	export const ELEMENT_TYPES = [
14	  'EVIDENCE', 'RULE', 'PERMISSION', 'NECESSARY_CONDITION', 'RISK',
15	];
16	
17	/**
18	 * Create an element object from input, validating required fields by type.
19	 * @param {object} input - Element fields from caller
20	 * @param {string} id - Unique element ID
21	 * @param {number} round - Round number when element is added
22	 * @returns {object} The created element
23	 */
24	export function createElement(input, id, round) {
25	  const {
26	    type, statement, source,
27	    grounding, collapse_test, reasoning_chain, rejected_alternatives,
28	    relieves, basis,
29	  } = input;
30	
31	  if (!ELEMENT_TYPES.includes(type)) {
32	    throw new Error(`Invalid type "${type}". Must be one of: ${ELEMENT_TYPES.join(', ')}`);
33	  }
34	  if (!statement) {
35	    throw new Error('statement is required and must be non-empty');
36	  }
37	
38	  // EVIDENCE: agent-sourced codebase facts — source must not be "designer"
39	  if (type === 'EVIDENCE') {
40	    if (!source) {
41	      throw new Error('EVIDENCE requires explicit source field');
42	    }
43	    if (source === 'designer') {
44	      throw new Error('EVIDENCE cannot have source "designer" — use RULE for designer declarations');
45	    }
46	  }
47	
48	  // RULE: designer-directed restriction — source must be "designer"
49	  if (type === 'RULE') {
50	    if (source !== 'designer') {
51	      throw new Error('RULE requires source "designer" — only the designer can create rules');
52	    }
53	  }
54	
55	  // PERMISSION: designer-directed relief — source must be "designer", relieves required
56	  if (type === 'PERMISSION') {
57	    if (source !== 'designer') {
58	      throw new Error('PERMISSION requires source "designer" — only the designer can grant permissions');
59	    }
60	    if (!relieves) {
61	      throw new Error('PERMISSION requires relieves field (what restriction is being relaxed)');
62	    }
63	  }
64	
65	  // NECESSARY_CONDITION: must have grounding, collapse_test, reasoning_chain
66	  if (type === 'NECESSARY_CONDITION') {
67	    if (!Array.isArray(grounding) || grounding.length === 0) {
68	      throw new Error('NECESSARY_CONDITION requires grounding (non-empty array of element IDs)');
69	    }
70	    if (!collapse_test) {
71	      throw new Error('NECESSARY_CONDITION requires collapse_test (what breaks if this is removed)');
72	    }
73	    if (!reasoning_chain) {
74	      throw new Error('NECESSARY_CONDITION requires reasoning_chain (IF...THEN structure)');
75	    }
76	  }
77	
78	  return {
79	    id,
80	    type,
81	    statement,
82	    source: source ?? null,
83	    grounding: Array.isArray(grounding) ? grounding : [],
84	    collapse_test: collapse_test ?? null,
85	    reasoning_chain: reasoning_chain ?? null,
86	    rejected_alternatives: Array.isArray(rejected_alternatives) ? rejected_alternatives : [],
87	    relieves: relieves ?? null,
88	    basis: Array.isArray(basis) ? basis : [],
89	    status: 'active',
90	    addedInRound: round,
91	    revisedInRound: null,
92	    revision: 0,
93	  };
94	}
95	
96	/**
97	 * Check that all IDs in an array exist in the elements map.
98	 * @param {string[]} refs - Array of element IDs
99	 * @param {Map} elements - Map of id -> element
100	 * @returns {string[]} Array of error strings for missing refs
101	 */
102	export function validateRefs(refs, elements) {
103	  const errors = [];
104	  for (const ref of refs) {
105	    if (!elements.has(ref)) {
106	      errors.push(`Reference "${ref}" does not exist`);
107	    }
108	  }
109	  return errors;
110	}
111	
112	/**
113	 * BFS from startId following grounding/basis links. Returns all reachable IDs.
114	 * Handles cycles (stops at revisited nodes). Skips withdrawn elements.
115	 * Follows `grounding` for NECESSARY_CONDITIONs, `basis` for others.
116	 * @param {Map} elements - Map of id -> element
117	 * @param {string} startId - Element to start traversal from
118	 * @returns {string[]} Array of all reachable element IDs (excluding startId)
119	 */
120	export function traverseGroundingChain(elements, startId) {
121	  const visited = new Set([startId]);
122	  const result = [];
123	  const startEl = elements.get(startId);
124	  if (!startEl) return result;
125	
126	  // Use grounding for NCs, basis for others
127	  const startRefs = startEl.type === 'NECESSARY_CONDITION'
128	    ? (startEl.grounding || [])
129	    : (startEl.basis || []);
130	  const queue = [...startRefs];
131	
132	  while (queue.length > 0) {
133	    const currentId = queue.shift();
134	    if (visited.has(currentId)) continue;
135	    visited.add(currentId);
136	
137	    const el = elements.get(currentId);
138	    if (!el || el.status === 'withdrawn') continue;
139	
140	    result.push(currentId);
141	
142	    const refs = el.type === 'NECESSARY_CONDITION'
143	      ? (el.grounding || [])
144	      : (el.basis || []);
145	    for (const ref of refs) {
146	      if (!visited.has(ref)) {
147	        queue.push(ref);
148	      }
149	    }
150	  }
151	
152	  return result;
153	}
154	
155	/**
156	 * Flags active elements citing withdrawn elements in their direct grounding/basis.
157	 * @param {Map} elements
158	 * @returns {Array<{type: string, element_id: string, cited_id: string, message: string}>}
159	 */
160	export function checkWithdrawnGrounding(elements) {
161	  const warnings = [];
162	  for (const [id, el] of elements) {
163	    if (el.status !== 'active') continue;
164	    const refs = el.type === 'NECESSARY_CONDITION'
165	      ? (el.grounding || [])
166	      : (el.basis || []);
167	    for (const ref of refs) {
168	      const cited = elements.get(ref);
169	      if (cited && cited.status === 'withdrawn') {
170	        warnings.push({
171	          type: 'withdrawn-grounding',
172	          element_id: id,
173	          cited_id: ref,
174	          message: `Active element "${id}" cites withdrawn element "${ref}"`,
175	        });
176	      }
177	    }
178	  }
179	  return warnings;
180	}
181	
182	/**
183	 * Flags NECESSARY_CONDITIONs whose grounding doesn't contain at least one
184	 * EVIDENCE, RULE, or PERMISSION (directly or through the chain).
185	 * @param {Map} elements
186	 * @returns {Array<{type: string, element_id: string, message: string}>}
187	 */
188	export function checkUngrounded(elements) {
189	  const warnings = [];
190	  const groundingTypes = new Set(['EVIDENCE', 'RULE', 'PERMISSION']);
191	
192	  for (const [id, el] of elements) {
193	    if (el.status !== 'active') continue;
194	    if (el.type !== 'NECESSARY_CONDITION') continue;
195	
196	    const chain = traverseGroundingChain(elements, id);
197	    const hasGrounding = chain.some(refId => {
198	      const dep = elements.get(refId);
199	      return dep && groundingTypes.has(dep.type);
200	    });
201	
202	    if (!hasGrounding) {
203	      warnings.push({
