11	
12	import { traverseGroundingChain } from './proof.js';
13	
14	export const STALL_WINDOW = 3;
15	
16	/**
17	 * Compute completeness metrics from the elements map.
18	 * @param {Map} elements
19	 * @returns {object}
20	 */
21	export function computeCompleteness(elements) {
22	  let total_elements = 0;
23	  let active_elements = 0;
24	  let condition_count = 0;
25	  let conditions_with_alternatives = 0;
26	  let conditions_with_collapse_test = 0;
27	  let rule_count = 0;
28	  let evidence_count = 0;
29	  let permission_count = 0;
30	  let risk_count = 0;
31	  let revision_count = 0;
32	
33	  for (const [, el] of elements) {
34	    total_elements++;
35	    if (el.status !== 'active') continue;
36	    active_elements++;
37	
38	    if (el.type === 'NECESSARY_CONDITION') {
39	      condition_count++;
40	      if (Array.isArray(el.rejected_alternatives) && el.rejected_alternatives.length > 0) {
41	        conditions_with_alternatives++;
42	      }
43	      if (el.collapse_test) {
44	        conditions_with_collapse_test++;
45	      }
46	    }
47	    if (el.type === 'RULE') rule_count++;
48	    if (el.type === 'EVIDENCE') evidence_count++;
49	    if (el.type === 'PERMISSION') permission_count++;
50	    if (el.type === 'RISK') risk_count++;
51	    if (el.revisedInRound !== null) revision_count++;
52	  }
53	
54	  return {
55	    total_elements,
56	    active_elements,
57	    condition_count,
58	    conditions_with_alternatives,
59	    conditions_with_collapse_test,
60	    rule_count,
61	    evidence_count,
62	    permission_count,
63	    risk_count,
64	    revision_count,
65	  };
66	}
67	
68	/**
69	 * For each active NECESSARY_CONDITION, check if all leaf nodes in its
70	 * grounding chain are EVIDENCE, RULE, or PERMISSION elements.
71	 * Returns ratio of grounded conditions to total.
72	 * Returns 1.0 if no active conditions exist.
73	 * @param {Map} elements
74	 * @returns {number} 0.0 - 1.0
75	 */
76	export function computeGroundingCoverage(elements) {
77	  const conditions = [];
78	  for (const [, el] of elements) {
79	    if (el.status === 'active' && el.type === 'NECESSARY_CONDITION') {
80	      conditions.push(el);
81	    }
82	  }
83	
84	  if (conditions.length === 0) return 1.0;
85	
86	  const leafTypes = new Set(['EVIDENCE', 'RULE', 'PERMISSION']);
87	  let grounded = 0;
88	
89	  for (const condition of conditions) {
90	    if (condition.grounding.length === 0) {
91	      continue; // no grounding at all — not covered
92	    }
93	
94	    const chain = traverseGroundingChain(elements, condition.id);
95	    const chainSet = new Set(chain);
96	    let allLeavesGrounded = true;
97	
98	    for (const refId of chain) {
99	      const el = elements.get(refId);
100	      if (!el) continue;
101	
102	      // Determine if this is a leaf: no refs within the chain
103	      const refs = el.type === 'NECESSARY_CONDITION'
104	        ? (el.grounding || [])
105	        : (el.basis || []);
106	      const refsInChain = refs.filter(r => chainSet.has(r));
107	
108	      if (refsInChain.length === 0) {
109	        // Leaf node — must be a grounding type
110	        if (!leafTypes.has(el.type)) {
111	          allLeavesGrounded = false;
112	          break;
113	        }
114	      }
115	    }
116	
117	    if (allLeavesGrounded) grounded++;
118	  }
119	
120	  return grounded / conditions.length;
121	}
122	
123	/**
124	 * Returns true if active NECESSARY_CONDITION count has not changed for
125	 * STALL_WINDOW consecutive rounds. Needs STALL_WINDOW + 1 entries in history.
126	 * @param {number[]} conditionCountHistory
127	 * @returns {boolean}
128	 */
129	export function detectStall(conditionCountHistory) {
130	  if (conditionCountHistory.length < STALL_WINDOW + 1) return false;
131	
132	  const recent = conditionCountHistory.slice(-(STALL_WINDOW + 1));
133	  const val = recent[0];
134	  return recent.every(v => v === val);
135	}
136	
137	/**
138	 * Detect if a challenge mode should fire. Checks in priority order:
139	 * ontologist, simplifier, contrarian.
140	 * @param {object} state - { round, elements, conditionCountHistory, elementCountHistory, challengeModesUsed }
141	 * @returns {{ mode: string|null, reason: string|null }}
142	 */
143	export function detectChallenge(state) {
144	  const { round, elements, conditionCountHistory, elementCountHistory, challengeModesUsed } = state;
145	
146	  // Ontologist: condition count stall detected and not used
147	  if (!challengeModesUsed.includes('ontologist') && detectStall(conditionCountHistory)) {
148	    return {
149	      mode: 'ontologist',
150	      reason: 'Condition count has not changed for 3 consecutive rounds — ontologist challenge triggered',
151	    };
152	  }
153	
154	  // Simplifier: condition count grew by >= 2 without any conditions being consolidated
155	  if (!challengeModesUsed.includes('simplifier') && conditionCountHistory.length >= 2) {
156	    const prev = conditionCountHistory[conditionCountHistory.length - 2];
157	    const curr = conditionCountHistory[conditionCountHistory.length - 1];
158	    const growth = curr - prev;
159	
160	    if (growth >= 2) {
161	      return {
162	        mode: 'simplifier',
163	        reason: `Condition count grew by ${growth} without consolidation — simplifier challenge triggered`,
164	      };
165	    }
166	  }
167	
168	  // Contrarian: round >= 2, any active NC grounded only in EVIDENCE (no RULE)
169	  if (!challengeModesUsed.includes('contrarian') && round >= 2) {
170	    for (const [, el] of elements) {
171	      if (el.status !== 'active' || el.type !== 'NECESSARY_CONDITION') continue;
172	
173	      const chain = traverseGroundingChain(elements, el.id);
174	      const hasRule = chain.some(refId => {
175	        const dep = elements.get(refId);
176	        return dep && dep.type === 'RULE';
177	      });
178	      const hasEvidence = chain.some(refId => {
179	        const dep = elements.get(refId);
180	        return dep && dep.type === 'EVIDENCE';
181	      });
182	
183	      // Grounded only in EVIDENCE, no RULE — agent deriving requirements from code alone
184	      if (hasEvidence && !hasRule) {
185	        return {
186	          mode: 'contrarian',
187	          reason: `Necessary condition "${el.id}" is grounded only in EVIDENCE with no RULE — contrarian challenge triggered`,
188	        };
189	      }
190	    }
191	  }
192	
193	  return { mode: null, reason: null };
194	}
195	
196	/**
197	 * Check whether closure (finishing the design proof) is permitted.
198	 * All conditions must pass.
199	 * @param {object} state - { elements, round, phaseTransitionRound }
200	 * @returns {{ permitted: boolean, reasons: string[] }}
201	 */
202	export function checkClosure(state) {
203	  const { elements, round, phaseTransitionRound } = state;
204	  const reasons = [];
205	
206	  let conditionCount = 0;
207	  let allGrounded = true;
208	  let allHaveCollapseTest = true;
209	  let anyWithAlternatives = false;
210	  let anyRevisedPostTransition = false;
211	  let hasIntegrityWarning = false;
212	
213	  for (const [, el] of elements) {
214	    if (el.status !== 'active') continue;
215	
216	    if (el.type === 'NECESSARY_CONDITION') {
217	      conditionCount++;
218	
219	      // Check grounding: must have at least one EVIDENCE/RULE/PERMISSION in chain
220	      const chain = traverseGroundingChain(elements, el.id);
221	      const groundingTypes = new Set(['EVIDENCE', 'RULE', 'PERMISSION']);
222	      const isGrounded = chain.some(refId => {
223	        const dep = elements.get(refId);
224	        return dep && groundingTypes.has(dep.type);
225	      });
226	      if (!isGrounded) allGrounded = false;
227	
228	      if (!el.collapse_test) allHaveCollapseTest = false;
229	
230	      if (Array.isArray(el.rejected_alternatives) && el.rejected_alternatives.length > 0) {
231	        anyWithAlternatives = true;
232	      }
233	    }
234	
235	    if (el.revisedInRound !== null && el.revisedInRound > phaseTransitionRound) {
236	      anyRevisedPostTransition = true;
237	    }
238	  }
239	
240	  // 1. All necessary conditions are grounded
241	  if (!allGrounded) {
242	    reasons.push('Not all necessary conditions are grounded in EVIDENCE, RULE, or PERMISSION');
243	  }
244	
245	  // 2. Every condition has a collapse test
246	  if (!allHaveCollapseTest) {
247	    reasons.push('Not all necessary conditions have collapse tests');
248	  }
249	
250	  // 3. At least one condition has rejected alternatives
251	  if (!anyWithAlternatives) {
252	    reasons.push('No necessary condition has rejected alternatives — at least one required');
253	  }
254	
255	  // 4. At least one element revised after designer interaction
256	  if (!anyRevisedPostTransition) {
257	    reasons.push('No element has been revised after phase transition');
258	  }
259	
260	  // 5. Minimum rounds
261	  if (round < 3) {
262	    reasons.push(`Current round (${round}) is below minimum (3)`);
263	  }
264	
265	  // 6. Must have at least one condition
266	  if (conditionCount === 0) {
267	    reasons.push('No active necessary conditions exist');
268	  }
269	
270	  return {
271	    permitted: reasons.length === 0,
272	    reasons,
273	  };
274	}
