    expect(loaded.concernsLocked).toBe(true);
    expect(loaded.ratificationLog).toHaveLength(2);
    expect(loaded.elements.get('RCON-1').ratification).toEqual({ ratifiedAtRound: 1, text: 'ok' });
  });
});
