      event: 'cleared-on-revise',
      target: op.target,
      round: current.round,
      fields: semanticFieldsChanged,
    });
  }
  target.revision++;
  target.revisedInRound = current.round;
  current.revisionLog.push({
    target: op.target,
    round: current.round,
    revision: target.revision,
  });
  revised.push(op.target);
  break;
}
