340	/**
341	 * Append a Concern to state. Refuses if Concerns list is locked.
342	 * @param {object} state
343	 * @param {{label: string, description?: string}} input
344	 * @returns {[string|null, object, string|null]} [concernId, newState, error]
345	 */
346	export function addConcern(state, { label, description }) {
347	  if (state.concernsLocked) {
348	    return [null, state, 'Concerns are locked; cannot add'];
349	  }
350	  const newState = structuredClone(state);
351	  newState.elements = cloneElements(state.elements);
352	  newState.concernCounter++;
353	  const id = `CERN-${newState.concernCounter}`;
354	  newState.concerns.push({ id, label, description: description ?? null });
355	  return [id, newState, null];
356	}
