359	 * Lock the Concerns list. Refuses on empty list or already-locked list.
360	 * @param {object} state
361	 * @returns {[object, string|null]} [newState, error]
362	 */
363	export function lockConcerns(state) {
364	  if (state.concernsLocked) {
365	    return [state, 'Concerns already locked'];
366	  }
367	  if (state.concerns.length === 0) {
368	    return [state, 'Cannot lock empty Concerns list'];
369	  }
370	  const newState = structuredClone(state);
371	  newState.elements = cloneElements(state.elements);
372	  newState.concernsLocked = true;
